import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.C60zNHNT.js";const m=JSON.parse('{"title":"ADR-003: Pure core behind injectable seams","description":"","frontmatter":{},"headers":[],"relativePath":"reference/decisions/ADR-003-pure-core-injectable-seams.md","filePath":"reference/decisions/ADR-003-pure-core-injectable-seams.md"}'),s={name:"reference/decisions/ADR-003-pure-core-injectable-seams.md"};function n(r,e,c,l,d,u){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-003-pure-core-behind-injectable-seams" tabindex="-1">ADR-003: Pure core behind injectable seams <a class="header-anchor" href="#adr-003-pure-core-behind-injectable-seams" aria-label="Permalink to &quot;ADR-003: Pure core behind injectable seams&quot;">​</a></h1><blockquote><p><strong>Date</strong>: 2026-06-28 <strong>Status</strong>: Accepted <strong>Source</strong>: RD-04 (rendering), RD-05 (color), RD-07 (host)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>A terminal engine is inherently side-effecting — it reads bytes from and writes escape sequences to a live TTY. But side-effecting code wired directly to <code>process.stdin</code>/<code>stdout</code> is hard to test and couples every subsystem to the host environment.</p><h2 id="options-considered" tabindex="-1">Options Considered <a class="header-anchor" href="#options-considered" aria-label="Permalink to &quot;Options Considered&quot;">​</a></h2><h3 id="option-a-subsystems-talk-to-node-streams-tty-directly" tabindex="-1">Option A: Subsystems talk to Node streams/TTY directly <a class="header-anchor" href="#option-a-subsystems-talk-to-node-streams-tty-directly" aria-label="Permalink to &quot;Option A: Subsystems talk to Node streams/TTY directly&quot;">​</a></h3><ul><li><strong>Pros</strong>: Less indirection; fewer interfaces.</li><li><strong>Cons</strong>: Untestable without a real terminal; rendering/decoding entangled with I/O; no way to substitute behaviour.</li></ul><h3 id="option-b-pure-functional-core-a-few-well-named-injectable-seams" tabindex="-1">Option B: Pure functional core + a few well-named injectable seams <a class="header-anchor" href="#option-b-pure-functional-core-a-few-well-named-injectable-seams" aria-label="Permalink to &quot;Option B: Pure functional core + a few well-named injectable seams&quot;">​</a></h3><ul><li><strong>Pros</strong>: Rendering (<code>serialize</code>), decoding (<code>decode</code>), and colour (<code>encodeStyle</code>) are pure transforms; the only I/O lives behind a <code>RuntimeAdapter</code>; capabilities use a <code>TerminalQuery</code> seam; the encoder is a <code>StyleEncoder</code> seam. Everything is unit-testable with fakes.</li><li><strong>Cons</strong>: A handful of interfaces to define and thread through.</li></ul><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p><strong>Chosen option</strong>: Option B — keep the core pure and isolate all side effects and substitutable behaviour behind three seams: <code>RuntimeAdapter</code> (host I/O), <code>TerminalQuery</code> (capability queries), and <code>StyleEncoder</code> (colour encoding).</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>Purity makes the bulk of the engine testable as plain functions: golden-screen tests drive a headless emulator, decoding is fuzzed, and byte-proportionality is asserted deterministically. The seams concentrate the untestable parts into small, mockable surfaces — the host&#39;s restore guarantee is proven with a fake adapter (see <a href="/jsvision/pr-preview/pr-53/reference/decisions/ADR-004-no-node-pty.html">ADR-004</a>), and <code>serialize</code> defaults to the RD-05 <code>encodeStyle</code> but accepts any encoder.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>High test coverage without a real TTY; deterministic specs.</li><li>Subsystems are decoupled and independently evolvable.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>Slightly more interface surface to define and document.</li></ul><h3 id="risks" tabindex="-1">Risks <a class="header-anchor" href="#risks" aria-label="Permalink to &quot;Risks&quot;">​</a></h3><ul><li>Seam interfaces must stay minimal so they do not leak host concerns into the pure core — kept in check by code review against the public surface.</li></ul>',20)])])}const b=t(s,[["render",n]]);export{m as __pageData,b as default};
